// Topic: iot/<nodeId>/parent
// Payload: <newParentId>
var parts = msg.topic.split('/');
var nodeId = parts[1];
var newParentId = msg.payload;

// para que el heartbeat checker sepa que este nodo sigue vivo
var known = flow.get('knownNodes') || [];
if (known.indexOf(nodeId) === -1) { known.push(nodeId); flow.set('knownNodes', known); }
flow.set('lastSeen_' + nodeId, Date.now());

msg.payload = JSON.stringify({
    nodeId: nodeId,
    newParentId: newParentId
});
msg.headers = {'Content-Type': 'application/json'};
msg.url = 'http://localhost:8080/parent-update';
return msg;

// Topic: iot/<nodeId>/msg
// Payload: <seqNum>
var parts = msg.topic.split('/');
var nodeId = parts[1];

// para que el heartbeat checker sepa que este nodo sigue vivo
var known = flow.get('knownNodes') || [];
if (known.indexOf(nodeId) === -1) { known.push(nodeId); flow.set('knownNodes', known); }
flow.set('lastSeen_' + nodeId, Date.now());

msg.payload = JSON.stringify({
    fromNodeId: nodeId,
    seqNum: parseInt(msg.payload)
});
msg.headers = {'Content-Type': 'application/json'};
msg.url = 'http://localhost:8080/app-msg';
return msg;

// Topic: iot/<nodeId>/crash
var parts = msg.topic.split('/');
var nodeId = parts[1];

msg.payload = JSON.stringify({ nodeId: nodeId });
msg.headers = {'Content-Type': 'application/json'};
msg.url = 'http://localhost:8080/node-crash';

// Also trigger recovery: restart node in Cooja via MQTT
var recoveryMsg = {
    topic: 'iot/' + nodeId + '/restart',
    payload: 'restart'
};
return [msg, recoveryMsg];

// Topic: iot/<nodeId>/recovered
// Publicado por serial-bridge cuando el nodo vuelve a dar heartbeats
var parts = msg.topic.split('/');
var nodeId = parts[1];

msg.payload = JSON.stringify({ nodeId: nodeId });
msg.headers = {'Content-Type': 'application/json'};
msg.url = 'http://localhost:8080/node-recovered';
return msg;

// Forward period change to Akka actor
// OJO: hay que leer nodeId/periodMs del payload ANTES de convertirlo a
// texto, si no msg.payload.nodeId sale undefined (bug que habia antes)
var nodeId = msg.payload.nodeId;
var periodMs = msg.payload.periodMs;

// para que el heartbeat checker calcule bien el timeout de este nodo
flow.set('period_' + nodeId, periodMs);

msg.headers = {'Content-Type': 'application/json'};
msg.payload = JSON.stringify({ nodeId: nodeId, periodMs: periodMs });
msg.url = 'http://localhost:8080/set-period';

// Also send to IoT node via MQTT
var mqttMsg = {
    topic: 'iot/' + nodeId + '/period',
    payload: String(periodMs)
};
return [msg, mqttMsg];

// corre cada 2s. Por cada nodo que conocemos (lo aprendimos en
// fn-parse-parent/fn-parse-app-msg), miramos si lleva demasiado sin
// dar señales de vida segun su propio periodo T, y si cambio de
// estado (vivo <-> crasheado) publicamos el evento correspondiente.
// Esta es la logica de coordinacion que antes vivia en el bridge, y
// que el enunciado pide que este aqui, en Node-RED.
var HEARTBEAT_MULTIPLIER = 3;
var DEFAULT_PERIOD_MS = 4000;
var now = Date.now();
var known = flow.get('knownNodes') || [];
var events = [];

known.forEach(function (nodeId) {
    var lastSeen = flow.get('lastSeen_' + nodeId) || 0;
    var period = flow.get('period_' + nodeId) || DEFAULT_PERIOD_MS;
    var crashed = flow.get('crashed_' + nodeId) || false;
    var timeoutMs = period * HEARTBEAT_MULTIPLIER;

    if (!crashed && (now - lastSeen) > timeoutMs) {
        flow.set('crashed_' + nodeId, true);
        events.push({ topic: 'iot/' + nodeId + '/crash', payload: '' });
    } else if (crashed && (now - lastSeen) <= timeoutMs) {
        flow.set('crashed_' + nodeId, false);
        events.push({ topic: 'iot/' + nodeId + '/recovered', payload: '' });
    }
});

return [events];
